private void inferPropertyTypesToMatchConstraint(
    JSType type, JSType constraint) {
  // Early exit if either type or constraint is null
  if (type == null || constraint == null) {
    return;
  }

  // Restricting the constraint to not null or undefined
  ObjectType constraintObj =
      ObjectType.cast(constraint.restrictByNotNullOrUndefined());

  // Ensure that the constraint is an object type and is a record type
  if (constraintObj != null && constraintObj.isRecordType()) {
    // Cast the type to ObjectType after restriction
    ObjectType objType = ObjectType.cast(type.restrictByNotNullOrUndefined());

    // Proceed only if objType is valid
    if (objType != null) {
      for (String prop : constraintObj.getOwnPropertyNames()) {
        JSType propType = constraintObj.getPropertyType(prop);

        // Check if the property is not already declared in objType
        if (!objType.isPropertyTypeDeclared(prop)) {
          JSType typeToInfer = propType;

          // If objType does not have the property, infer its type accordingly
          if (!objType.hasProperty(prop)) {
            typeToInfer =
                getNativeType(VOID_TYPE).getLeastSupertype(propType);
          }

          // Define the inferred property in objType
          objType.defineInferredProperty(prop, typeToInfer, null);
        }
      }
    }
  }
}
